1	/**
2	 * PromptContext builder — assembles the context object fed to assemblePrompt().
3	 *
4	 * Responsibilities (feat-prompt-asm, prompt-template-spec.md §4):
5	 *   1. Read architecture.md and progress.md from the worktree (or "" if absent).
6	 *   2. Parse item.data as an opaque JSON blob (AC-4: no named field access).
7	 *   3. Project item_state from harness-state columns (status, current_phase,
8	 *      retry_count, blocked_reason).
9	 *   4. Read handoff.json and serialize its entries array as the {{handoff}} value.
10	 *   5. Call git.logRecent(20) for {{git_log_recent}}.
11	 *   6. Call git.diffRange(from, to) for {{recent_diff}} when refs are provided.
12	 *   7. Return a fully-populated PromptContext; every key that appears in a
13	 *      standard template is present (optional keys use "" for absent content).
14	 *
15	 * Non-responsibilities:
16	 *   - Does NOT apply state-machine transitions.
17	 *   - Does NOT spawn processes.
18	 *   - Does NOT write to SQLite.
19	 *
20	 * I/O lives here (RC-1): fs.readFileSync calls for architecture.md, progress.md,
21	 * and handoff.json are in this file, not in assembler.ts.
22	 *
23	 * Review criteria compliance:
24	 *   RC-3  item.data is parsed as an opaque blob; no harness-level field names
25	 *         are accessed inside this module beyond what template vars reference.
26	 *         The parsed object is stored whole under the "item" key.
27	 */
28	
29	import fs from 'node:fs';
30	import path from 'node:path';
31	import type { PromptContext } from './engine.js';
32	
33	// ---------------------------------------------------------------------------
34	// Row projections — typed wrappers over SQLite rows
35	// ---------------------------------------------------------------------------
36	
37	/**
38	 * Projection of the columns from the `workflows` table that the context
39	 * builder reads. The caller is responsible for querying SQLite and producing
40	 * this plain object.
41	 */
42	export interface WorkflowRow {
43	  id: string;
44	  name: string;
45	  current_stage: string | null;
46	}
47	
48	/**
49	 * Projection of the columns from the `items` table that the context builder
50	 * reads.
51	 *
52	 * `data` is an opaque JSON blob. The builder parses it and stores the whole
53	 * parsed object under the "item" key in PromptContext. No named fields within
54	 * `data` are accessed by the builder (AC-4, RC-3).
55	 */
56	export interface ItemRow {
57	  id: string;
58	  data: string;              // opaque JSON blob from SQLite TEXT column
59	  status: string;
60	  current_phase: string | null;
61	  retry_count: number;
62	  blocked_reason: string | null;
63	}
64	
65	// ---------------------------------------------------------------------------
66	// ItemStateProjection — harness-tracked state surfaced to templates
67	// ---------------------------------------------------------------------------
68	
69	/**
70	 * Harness-level state fields exposed as {{item_state}} in templates (Issue 3,
71	 * prompt-template-spec.md §3.2). These are the *harness* columns, not the
72	 * opaque item.data fields.
73	 *
74	 * Templates access these via:
75	 *   {{item_state}}                → full JSON object
76	 *   {{item_state.status}}         → string
77	 *   {{item_state.current_phase}}  → string or [MISSING:...] if null
78	 *   {{item_state.retry_count}}    → JSON-serialized number
79	 *   {{item_state.blocked_reason}} → string or [MISSING:...] if null
80	 */
81	export interface ItemStateProjection {
82	  status: string;
83	  current_phase: string | null;
84	  retry_count: number;
85	  blocked_reason: string | null;
86	}
87	
88	// ---------------------------------------------------------------------------
89	// HandoffFile — typed shape of handoff.json
90	// ---------------------------------------------------------------------------
91	
92	/**
93	 * Parsed shape of handoff.json written by previous phase sessions.
94	 * The entries array is the canonical handoff payload; the rest is metadata.
95	 */
96	export interface HandoffEntry {
97	  phase: string;
98	  attempt: number;
99	  ts: string;
100	  [key: string]: unknown;
101	}
102	
103	export interface HandoffFile {
104	  feature?: string;
105	  entries?: HandoffEntry[];
106	  [key: string]: unknown;
107	}
108	
109	// ---------------------------------------------------------------------------
110	// GitHelper — injected abstraction for git operations (no shell in assembler)
111	// ---------------------------------------------------------------------------
112	
113	/**
114	 * Git helper interface injected into the context builder.
115	 *
116	 * The builder calls these functions; the implementation uses execFileAsync('git').
117	 * Injecting as a plain object enables unit testing without a real git repository.
118	 */
119	export interface GitHelper {
120	  /**
121	   * Returns the last `n` commits formatted for prompt injection.
122	   * Equivalent to: git log --oneline -n <n>
123	   */
124	  logRecent(n: number): Promise<string>;
125	
126	  /**
127	   * Returns the diff between two git refs.
128	   * Equivalent to: git diff <from> <to>
129	   * Returns "" if either ref is absent.
130	   */
131	  diffRange(from: string, to: string): Promise<string>;
132	}
133	
134	// ---------------------------------------------------------------------------
135	// PromptContextInputs — caller-supplied inputs to buildPromptContext()
136	// ---------------------------------------------------------------------------
137	
138	export interface PromptContextInputs {
139	  /** Workflow row from SQLite. */
140	  workflow: WorkflowRow;
141	  /** Current stage configuration (id and run mode). */
142	  stage: { id: string; run: 'once' | 'per-item' };
143	  /** Item row from SQLite. Present only in per-item stage phases. */
144	  item?: ItemRow;
145	  /** Absolute path to the worktree directory. */
146	  worktreePath: string;
147	  /**
148	   * Absolute path to architecture.md.
149	   * Defaults to <worktreePath>/architecture.md if not provided.
150	   */
151	  architectureMdPath?: string;
152	  /**
153	   * Absolute path to progress.md.
154	   * Defaults to <worktreePath>/progress.md if not provided.
155	   */
156	  progressMdPath?: string;
157	  /**
158	   * Absolute path to handoff.json.
159	   * Defaults to <worktreePath>/handoff.json if not provided.
160	   */
161	  handoffPath?: string;
162	  /** Injected git helper. */
163	  git: GitHelper;
164	  /**
165	   * Start git ref for recent_diff. If absent, recent_diff is "".
166	   */
167	  diffFrom?: string;
168	  /**
169	   * End git ref for recent_diff. Defaults to "HEAD" when diffFrom is present.
170	   */
171	  diffTo?: string;
172	  /**
173	   * User-injected context string (D43). Empty string if none.
174	   */
175	  userInjectedContext?: string;
176	}
177	
178	// ---------------------------------------------------------------------------
179	// buildPromptContext — public builder
180	// ---------------------------------------------------------------------------
181	
182	/**
183	 * Builds a PromptContext ready for assemblePrompt().
184	 *
185	 * The returned context is fully populated: every standard template variable
186	 * has a value. Optional content (architecture.md, handoff.json, etc.) uses
187	 * "" when the file is absent.
188	 *
189	 * AC-4/RC-3: item.data is parsed as an opaque blob and stored whole under
190	 * ctx["item"]. The builder does not access any named fields within item.data.
191	 *
192	 * @throws {SyntaxError} if item.data is not valid JSON (caller should treat
193	 *   this as a configuration error — the item manifest must contain valid JSON).
194	 */
195	export async function buildPromptContext(inputs: PromptContextInputs): Promise<PromptContext> {
196	  const {
197	    workflow,
198	    stage,
199	    item,
200	    worktreePath,
201	    git,
202	    userInjectedContext = '',
203	  } = inputs;
204	
205	  // ---------------------------------------------------------------------------
206	  // Read architecture.md (or "")
207	  // ---------------------------------------------------------------------------
208	  const archPath = inputs.architectureMdPath ?? path.join(worktreePath, 'architecture.md');
209	  const architecture_md = readFileOrEmpty(archPath);
210	
211	  // ---------------------------------------------------------------------------
212	  // Call git.logRecent(20) for {{git_log_recent}}
213	  // ---------------------------------------------------------------------------
214	  const git_log_recent = await git.logRecent(20);
215	
216	  // ---------------------------------------------------------------------------
217	  // Base context — available in all phases
218	  // ---------------------------------------------------------------------------
219	  const ctx: PromptContext = {
220	    workflow_name: workflow.name,
221	    stage_id: stage.id,
222	    architecture_md,
223	    git_log_recent,
224	    user_injected_context: userInjectedContext,
225	  };
226	
227	  // ---------------------------------------------------------------------------
228	  // Per-item phase variables (stage.run === 'per-item' with an item present)
229	  // ---------------------------------------------------------------------------
230	  if (stage.run === 'per-item' && item !== undefined) {
231	    // AC-4/RC-3: parse item.data as an opaque blob — no named field access.
232	    // The entire parsed object is stored under "item"; the template engine
233	    // handles field access via dot traversal ({{item.description}}, etc.).
234	    const parsedItemData = JSON.parse(item.data) as Record<string, unknown>;
235	
236	    // Project harness-level state (Issue 3). These are the columns from the
237	    // items table, NOT from item.data — the distinction is important (AC-1).
238	    const item_state: ItemStateProjection = {
239	      status: item.status,
240	      current_phase: item.current_phase,
241	      retry_count: item.retry_count,
242	      blocked_reason: item.blocked_reason,
243	    };
244	
245	    // Read progress.md (or "")
246	    const progressPath = inputs.progressMdPath ?? path.join(worktreePath, 'progress.md');
247	    const progress_md = readFileOrEmpty(progressPath);
248	
249	    // Read handoff.json and serialize entries (AC-6: {{handoff}})
250	    const handoffPath = inputs.handoffPath ?? path.join(worktreePath, 'handoff.json');
251	    const handoff = readHandoffEntries(handoffPath);
252	
253	    // Compute recent_diff if refs are provided (or "")
254	    let recent_diff = '';
255	    if (inputs.diffFrom) {
256	      const diffTo = inputs.diffTo ?? 'HEAD';
257	      recent_diff = await git.diffRange(inputs.diffFrom, diffTo);
258	    }
259	
260	    Object.assign(ctx, {
261	      item_id: item.id,
262	      item: parsedItemData,
263	      item_state: item_state as unknown as Record<string, unknown>,
264	      progress_md,
265	      handoff,
266	      recent_diff,
267	    });
268	  }
269	
270	  return ctx;
271	}
272	
273	// ---------------------------------------------------------------------------
274	// Private helpers
275	// ---------------------------------------------------------------------------
276	
277	/**
278	 * Reads a UTF-8 text file and returns its contents, or "" if the file does
279	 * not exist. Other errors (permission denied, I/O error) are re-thrown.
280	 */
281	function readFileOrEmpty(filePath: string): string {
282	  try {
283	    return fs.readFileSync(filePath, 'utf8');
284	  } catch (err: unknown) {
285	    const e = err as NodeJS.ErrnoException;
286	    if (e.code === 'ENOENT') {
287	      return '';
288	    }
289	    throw err;
290	  }
291	}
292	
293	/**
294	 * Reads handoff.json and returns the entries array as a pretty-printed JSON
295	 * string (AC-6: {{handoff}} variable).
296	 *
297	 * The "most-recent handoff entries" are all entries from the current
298	 * handoff.json file (the file is rewritten each workflow run, so reading it
299	 * gives the up-to-date state).
300	 *
301	 * Returns "" if the file is absent (no handoff entries yet).
302	 * Returns "[]" if the file exists but has no entries array.
303	 *
304	 * @throws {SyntaxError} if the file exists but is not valid JSON.
305	 */
306	function readHandoffEntries(filePath: string): string {
307	  const raw = readFileOrEmpty(filePath);
308	  if (raw === '') {
309	    return '';
310	  }
311	  const parsed = JSON.parse(raw) as HandoffFile;
312	  const entries = parsed.entries ?? [];
313	  return JSON.stringify(entries, null, 2);
314	}
